/**
 * Phase 2 Data Generator
 *
 * Per Blueprint Ch 9 (Phase 2, weeks 4-6):
 *   From the per-date entries generated by the main batch, derive:
 *     - Person data (top 50K people, indexed by birthday)
 *     - Category×date data (14 categories × 366 days)
 *     - Year-page data (~150 years, 1875-2025)
 *     - Days-since/until index (top 5K events)
 *     - Zodiac/generation data (Western, Chinese, generation groupings)
 *     - Holiday-year data (movable feasts + fixed for next 3 years)
 *     - Country-lens data (top 10 countries)
 *     - National day data (top 200 international days)
 *
 * Usage:
 *   node scripts/generate-otd-phase2.js
 *   node scripts/generate-otd-phase2.js --input /tmp/otd-data-final/dates/ --output /tmp/otd-phase2/
 */

const fs = require('fs');
const path = require('path');

const { extractPersons, buildBirthdayTwinIndex } = require('./lib/persons');
const { buildCategoryDate, saveCategoryDate, CATEGORY_LIST } = require('./lib/category-date');
const { buildYearPages, saveYearPages } = require('./lib/year-pages');
const { buildDaysSinceIndex, saveDaysSinceIndex } = require('./lib/days-since');
const { saveZodiacIndex } = require('./lib/zodiac');
const { buildHolidayYears } = require('./lib/holiday-year');
const { TOP_FIXED_HOLIDAYS, computeMovableFeasts } = require('./lib/holiday-year');

const INPUT_DIR = process.env.INPUT_DIR || '/tmp/otd-data-final/dates';
const OUTPUT_DIR = process.env.OUTPUT_DIR || '/tmp/otd-phase2';

const TOP_COUNTRIES = ['US', 'GB', 'CA', 'AU', 'IN', 'BR', 'JP', 'DE', 'FR', 'CN'];

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  console.log('========================================');
  console.log('🛠️  PHASE 2 DATA GENERATOR');
  console.log('========================================');
  console.log(`Input: ${INPUT_DIR}`);
  console.log(`Output: ${OUTPUT_DIR}`);

  if (!fs.existsSync(INPUT_DIR)) {
    console.error(`Input dir not found: ${INPUT_DIR}`);
    process.exit(1);
  }
  if (!fs.existsSync(OUTPUT_DIR)) {
    fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  const startTime = Date.now();

  // ---- Load all entries ----
  console.log('\n[1/8] Loading entries...');
  const allEntries = [];
  const dateFiles = fs.readdirSync(INPUT_DIR).filter(f => f.endsWith('.json'));
  for (const file of dateFiles) {
    try {
      const content = fs.readFileSync(path.join(INPUT_DIR, file), 'utf-8');
      const entries = JSON.parse(content);
      allEntries.push(...entries);
    } catch (e) {
      console.warn(`  ${file}: ${e.message}`);
    }
  }
  console.log(`  Loaded ${allEntries.length} entries from ${dateFiles.length} dates`);

  // ---- Person data ----
  console.log('\n[2/8] Extracting persons...');
  const persons = extractPersons(allEntries);
  console.log(`  ${persons.length} unique persons`);

  // Top 50K by notability
  const top50k = persons
    .sort((a, b) => (b.notability_score || 0) - (a.notability_score || 0))
    .slice(0, 50_000);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'persons-top-50k.json'), JSON.stringify(top50k, null, 0));
  console.log(`  Top 50K saved`);

  // Birthday-twin index (top 50 per day)
  const birthdayIndex = buildBirthdayTwinIndex(persons);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'birthday-twin.json'), JSON.stringify(birthdayIndex, null, 0));
  console.log(`  Birthday-twin: ${Object.keys(birthdayIndex).length} dates`);

  // ---- Category×date ----
  console.log('\n[3/8] Building category×date data...');
  const categoryData = buildCategoryDate(allEntries);
  const catDir = path.join(OUTPUT_DIR, 'categories');
  const catSummary = saveCategoryDate(categoryData, catDir);
  console.log(`  Categories: ${Object.keys(catSummary).join(', ')}`);

  // ---- Year pages ----
  console.log('\n[4/8] Building year pages...');
  const yearData = buildYearPages(allEntries);
  const yearDir = path.join(OUTPUT_DIR, 'years');
  const yearCount = saveYearPages(yearData, yearDir);
  console.log(`  ${yearCount} years`);

  // ---- Days-since/until ----
  console.log('\n[5/8] Building days-since/until index...');
  const daysIndex = buildDaysSinceIndex(allEntries);
  const daysCount = saveDaysSinceIndex(daysIndex, path.join(OUTPUT_DIR, 'days-since-index.json'));
  console.log(`  Top ${daysCount} events indexed`);

  // ---- Zodiac/generation ----
  console.log('\n[6/8] Building zodiac/generation index...');
  const zodiacStats = saveZodiacIndex(persons, path.join(OUTPUT_DIR, 'zodiac'));
  console.log(`  ${Object.keys(zodiacStats.western).length} Western signs, ${Object.keys(zodiacStats.chinese).length} Chinese zodiacs, ${Object.keys(zodiacStats.generations).length} generations`);

  // ---- Holiday-year ----
  console.log('\n[7/8] Building holiday-year data...');
  const currentYear = new Date().getFullYear();
  const holidayYears = buildHolidayYears(currentYear, currentYear + 3);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'holiday-years.json'), JSON.stringify(holidayYears, null, 0));
  console.log(`  ${Object.keys(holidayYears).length} years (${currentYear}-${currentYear + 3})`);

  // ---- Country-lens ----
  console.log('\n[8/8] Building country-lens data...');
  const countryLens = buildCountryLens(allEntries, TOP_COUNTRIES);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'country-lens.json'), JSON.stringify(countryLens, null, 0));
  console.log(`  ${TOP_COUNTRIES.length} countries indexed`);

  const duration = ((Date.now() - startTime) / 1000).toFixed(1);
  console.log('\n========================================');
  console.log('✅ PHASE 2 COMPLETE');
  console.log('========================================');
  console.log(`Duration: ${duration}s`);
  console.log(`Output: ${OUTPUT_DIR}/`);
}

/**
 * Build country-lens data: for each (country, date), aggregate events tied to that country.
 */
function buildCountryLens(entries, countries) {
  const result = {};
  for (const cc of countries) {
    result[cc] = {};

    for (const e of entries) {
      // Match by country_code
      if (e.country_code !== cc) continue;
      if (!e.month || !e.day) continue;
      const key = `${String(e.month).padStart(2, '0')}-${String(e.day).padStart(2, '0')}`;
      if (!result[cc][key]) result[cc][key] = [];
      result[cc][key].push({
        title: e.title,
        description: e.description,
        year: e.year,
        type: e.type,
        wikipedia_url: e.wikipedia_url,
        rank_score: e.rank_score || 0
      });
    }

    // Sort each by rank desc
    for (const key of Object.keys(result[cc])) {
      result[cc][key].sort((a, b) => (b.rank_score || 0) - (a.rank_score || 0));
    }
  }
  return result;
}

if (require.main === module) {
  main().catch(err => {
    console.error('Fatal:', err);
    process.exit(1);
  });
}

module.exports = { main };
